package conditions;

public class loops {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		//for loop
		//print numbers from 1 to 100
		
		for (int i=0; i<=100;i++) {
			System.out.println(i);
		}
		
		//While loop
		//print numbers from 1 to 10
		int i=0;
		while(i<=10) {
			System.out.println(i);
			i++;
		}
		
		//Do while loop
		int j=0;
		do {
			j++;
			System.out.println(j);
		} while (j<10);

	}

}
